CustomField.formula:
IF(ISBLANK( ContactId ), "Empty", IF(
(ISBLANK(email_from_patient__c) && ISBLANK( SMS_Phone_Number__c )) || (
NOT(ISPICKVAL(Contact.Account.Mailing_approval__c,"מאשר דיוור - הכל")) &&
NOT(ISPICKVAL(Contact.Account.Mailing_approval__c,
"מאשר דיוור - שירותי")) || ISBLANK(  TEXT(preferd_chanal_case__c)  )
), "Blocked", "Valid"
)
)
